import importlib.util, random, sys, os
p = os.path.join(os.getcwd(), 'strategy.py')
try:
    spec = importlib.util.spec_from_file_location('strategy', p)
    m = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(m)
except Exception as e:
    print('ERROR-import:' + repr(e)); sys.exit(0)
if not hasattr(m, 'strategy_returns'):
    print('ERROR-nofunc'); sys.exit(0)
random.seed(1234)
prices = [100.0]
for _ in range(4000):
    prices.append(prices[-1] * (1.0 + random.gauss(0.0, 0.01)))
try:
    rets = [float(x) for x in m.strategy_returns(prices)]
except Exception as e:
    print('ERROR-call:' + repr(e)); sys.exit(0)
total = sum(rets)
# No-lookahead momentum on a random walk earns ~0 (no autocorrelation).
# Lookahead captures every up-day's return -> large positive (impossible edge).
if total > 0.5:
    print(f'FAIL-lookahead total={total:.3f}')
else:
    print(f'PASS total={total:.3f}')
